import unittestfrom htmlnode import HTMLNode,LeafNode, ParentNode, text_node_to_html_node, markdown_to_html_nodefrom textnode import TextNode, TextTypeclass TestHTMLNode(unittest.TestCase):    def test_eq(self):        node = HTMLNode(tag="foo", value="31", children="adsd", props={"a":2})        self.assertEqual(node.tag, "foo")    def text_repr(self):        node = HTMLNode(tag="foo", value="31", children="adsd", props={"a":2})        self.assertEqual(str(node), """HTMLNode(            tag=foo,             value=31,             children=adsd,            props={'a': 2})""")    def text_props_to_html(self):        node = HTMLNode(tag="foo", value="31", children="adsd", props={"a":2})        self.assertEqual(node.props_to_html(), 'a="2"')class TestLeafNode(unittest.TestCase):    def test_leaf_to_html_p(self):        node = LeafNode("p", "Hello, world!")        self.assertEqual(node.to_html(), "<p>Hello, world!</p>")class TestParentNode(unittest.TestCase):       def test_to_html_with_children(self):        child_node = LeafNode("span", "child")        parent_node = ParentNode("div", [child_node])        self.assertEqual(parent_node.to_html(), "<div><span>child</span></div>")        def test_to_html_with_grandchildren(self):        grandchild_node = LeafNode("b", "grandchild")        child_node = ParentNode("span", [grandchild_node])        parent_node = ParentNode("div", [child_node])        self.assertEqual(            parent_node.to_html(),            "<div><span><b>grandchild</b></span></div>",        )                class TestTextNodetoHTMLNode(unittest.TestCase):            def test_text(self):        node = TextNode("This is a text node", TextType.TEXT)        html_node = text_node_to_html_node(node)        self.assertEqual(html_node.tag, None)        self.assertEqual(html_node.value, "This is a text node")class TestMarkdownToHtmlNode(unittest.TestCase):    def test_paragraphs(self):        md = """This is **bolded** paragraphtext in a ptag hereThis is another paragraph with _italic_ text and `code` here"""        node = markdown_to_html_node(md)        html = node.to_html()        self.assertEqual(            html,            "<div><p>This is <b>bolded</b> paragraph text in a p tag here</p><p>This is another paragraph with <i>italic</i> text and <code>code</code> here</p></div>",        )    def test_codeblock(self):        md = """```This is text that _should_ remainthe **same** even with inline stuff```"""        node = markdown_to_html_node(md)        html = node.to_html()        self.assertEqual(            html,            "<div><pre><code>This is text that _should_ remain\nthe **same** even with inline stuff\n</code></pre></div>",        )    def test_headings(self):        md = """# Heading one## Heading two### Heading three"""        node = markdown_to_html_node(md)        html = node.to_html()        self.assertEqual(            html,            "<div><h1>Heading one</h1><h2>Heading two</h2><h3>Heading three</h3></div>",        )    def test_heading_with_inline(self):        md = "## A heading with **bold** and _italic_"        node = markdown_to_html_node(md)        html = node.to_html()        self.assertEqual(            html,            "<div><h2>A heading with <b>bold</b> and <i>italic</i></h2></div>",        )    def test_quote(self):        md = """> This is a quote> that spans multiple lines"""        node = markdown_to_html_node(md)        html = node.to_html()        self.assertEqual(            html,            "<div><blockquote>This is a quote\nthat spans multiple lines</blockquote></div>",        )    def test_quote_with_inline(self):        md = "> A quote with **bold** text"        node = markdown_to_html_node(md)        html = node.to_html()        self.assertEqual(            html,            "<div><blockquote>A quote with <b>bold</b> text</blockquote></div>",        )    def test_unordered_list(self):        md = """- First item- Second item- Third item"""        node = markdown_to_html_node(md)        html = node.to_html()        self.assertEqual(            html,            "<div><ul><li>First item</li><li>Second item</li><li>Third item</li></ul></div>",        )    def test_unordered_list_with_inline(self):        md = """- Item with **bold**- Item with _italic_"""        node = markdown_to_html_node(md)        html = node.to_html()        self.assertEqual(            html,            "<div><ul><li>Item with <b>bold</b></li><li>Item with <i>italic</i></li></ul></div>",        )    def test_ordered_list(self):        md = """1. First item2. Second item3. Third item"""        node = markdown_to_html_node(md)        html = node.to_html()        self.assertEqual(            html,            "<div><ol><li>First item</li><li>Second item</li><li>Third item</li></ol></div>",        )    def test_ordered_list_with_inline(self):        md = """1. Item with **bold**2. Item with `code`"""        node = markdown_to_html_node(md)        html = node.to_html()        self.assertEqual(            html,            "<div><ol><li>Item with <b>bold</b></li><li>Item with <code>code</code></li></ol></div>",        )    def test_mixed_blocks(self):        md = """# TitleA paragraph with _italic_ text.- list item one- list item two"""        node = markdown_to_html_node(md)        html = node.to_html()        self.assertEqual(            html,            "<div><h1>Title</h1><p>A paragraph with <i>italic</i> text.</p><ul><li>list item one</li><li>list item two</li></ul></div>",        )if __name__ == "__main__":    unittest.main()